<?php

declare(strict_types=1);

namespace PhpOffice\PhpSpreadsheetTests\Writer\Html;

use PhpOffice\PhpSpreadsheet\Reader\Xlsx as XlsxReader;
use PhpOffice\PhpSpreadsheet\Writer\Html as HtmlWriter;
use PHPUnit\Framework\TestCase;

class HtmlTableFormatWithConditionalTest extends TestCase
{
    private string $data = '';

    protected function setUp(): void
    {
        $file = 'tests/data/Writer/Html/HtmlTableFormatTest.xlsx';
        $reader = new XlsxReader();
        $spreadsheet = $reader->load($file);
        $writer = new HtmlWriter($spreadsheet);
        $writer->setConditionalFormatting(true);
        $writer->setTableFormats(true);
        $this->data = $writer->generateHtmlAll();
        $spreadsheet->disconnectWorksheets();
    }

    #[\PHPUnit\Framework\Attributes\DataProvider('tableFormatWithConditionalProvider')]
    public function testHtmlTableFormatOutputWithConditional(int $rowNumber, array $expectedMatches): void
    {
        self::assertSame(1, preg_match('~<tr class="row' . $rowNumber . '".+?</tr>~ms', $this->data, $matches));
        foreach ($expectedMatches as $i => $expected) {
            self::assertStringContainsString($expected, $matches[0]);
        }
    }

